// Validate required fields and build a clean Content_Calendar row
try {
  const body = $input.first().json.body || $input.first().json;

  if (!body.topic) throw new Error('Missing required field: topic');
  if (!body.platform) throw new Error('Missing required field: platform');

  const today = new Date().toISOString().split('T')[0];
  const id = body.id || today.replace(/-/g, '') + '-' + Math.floor(Math.random() * 900 + 100);

  const pillarNames = {
    '1': 'AI Automation Systems & Processes',
    '2': 'Success Stories & Case Studies',
    '3': 'Healthcare Automation',
    '4': 'AI Myths & Misconceptions',
    '5': 'Industry Insights',
    '6': 'Q&A & Concerns',
    '7': 'Behind-the-Scenes & Personal'
  };

  const pillar = String(body.pillar || '1');

  return [{
    json: {
      id,
      pillar,
      pillar_name: body.pillar_name || pillarNames[pillar] || 'AI Automation Systems & Processes',
      platform: body.platform || 'LinkedIn',
      content_type: body.content_type || 'text',
      topic: body.topic,
      hook: body.hook || '',
      body: body.body || '',
      cta: body.cta || 'Book a discovery call: https://cal.com/reginald-johnson-fphjbi/discovery',
      image_url: body.image_url || '',
      scheduled_date: body.scheduled_date || today,
      scheduled_time: body.scheduled_time || '08:00',
      status: body.status || 'draft',
      posted_at: '',
      post_url: '',
      impressions: '',
      engagement: '',
      notes: body.notes || 'Added via Sheet Writer webhook'
    }
  }];
} catch (error) {
  console.error('Validate & Build Row:', error.message);
  throw new Error('Validation failed: ' + error.message);
}
